<?php$host     = getenv('DB_HOST');$port     = getenv('DB_PORT');$dbname   = getenv('DB_NAME');$user     = getenv('DB_USER');$password = getenv('DB_PASS');try {    $dsn = "pgsql:host=$host;port=$port;dbname=$dbname;sslmode=require";    $pdo = new PDO($dsn, $user, $password, [        PDO::ATTR_ERRMODE            => PDO::ERRMODE_EXCEPTION,        PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,        PDO::ATTR_EMULATE_PREPARES   => true,    ]);} catch (PDOException $e) {    if (ob_get_level()) ob_end_clean();    header('Content-Type: application/json; charset=utf-8');    http_response_code(500);    echo json_encode(['sucesso' => false, 'mensagem' => 'Erro de conexão com o banco.']);    exit;}define('SB_URL',        getenv('SB_URL'));define('SB_KEY',        getenv('SB_KEY'));define('SB_SECRET_KEY', getenv('SB_SECRET_KEY'));function gerenciarFotoSupabase($arquivoTmp, $nomeAntigo = null) {    if ($nomeAntigo && $nomeAntigo !== 'default.png') {        $ch = curl_init(SB_URL . "/storage/v1/object/fotos/" . $nomeAntigo);        curl_setopt_array($ch, [            CURLOPT_CUSTOMREQUEST => "DELETE",            CURLOPT_RETURNTRANSFER => true,            CURLOPT_HTTPHEADER => [                "Authorization: Bearer " . SB_SECRET_KEY,                "apikey: " . SB_SECRET_KEY            ],        ]);        curl_exec($ch);        curl_close($ch);    }    if (!$arquivoTmp) return 'default.png';    $extensao = pathinfo($_FILES['foto_perfil']['name'], PATHINFO_EXTENSION);    $novoNome = uniqid() . "." . $extensao;    $ch = curl_init(SB_URL . "/storage/v1/object/fotos/" . $novoNome);    curl_setopt_array($ch, [        CURLOPT_CUSTOMREQUEST => "POST",        CURLOPT_POSTFIELDS => file_get_contents($arquivoTmp),        CURLOPT_RETURNTRANSFER => true,        CURLOPT_HTTPHEADER => [            "Authorization: Bearer " . SB_SECRET_KEY,            "apikey: " . SB_SECRET_KEY,            "Content-Type: " . $_FILES['foto_perfil']['type']        ],    ]);    curl_exec($ch);    $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);    curl_close($ch);    return ($httpCode >= 200 && $httpCode < 300) ? $novoNome : false;}function fazerUploadPortfolioSupabase($arquivoTmp, $nomeOriginal) {    $extensao = pathinfo($nomeOriginal, PATHINFO_EXTENSION);    // Salvamos dentro da subpasta 'portfolio/' para organizar    $novoNome = "portfolio/" . uniqid() . "." . $extensao;        $ch = curl_init(SB_URL . "/storage/v1/object/fotos/" . $novoNome);    curl_setopt($ch, CURLOPT_CUSTOMREQUEST, "POST");    curl_setopt($ch, CURLOPT_POSTFIELDS, file_get_contents($arquivoTmp));    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);    curl_setopt($ch, CURLOPT_HTTPHEADER, [        "Authorization: Bearer " . SB_SECRET_KEY,        "apikey: " . SB_SECRET_KEY,        "Content-Type: image/" . $extensao // Simplificado    ]);        $resposta = curl_exec($ch);    $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);    curl_close($ch);    return ($httpCode === 200) ? $novoNome : false;}function apagarArquivoSupabase($caminhoRelativo) {    if (!$caminhoRelativo || $caminhoRelativo === 'default.png') return false;    // Remove barras extras se existirem    $caminhoRelativo = ltrim($caminhoRelativo, '/');    $ch = curl_init(SB_URL . "/storage/v1/object/fotos/" . $caminhoRelativo);    curl_setopt($ch, CURLOPT_CUSTOMREQUEST, "DELETE");    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);    curl_setopt($ch, CURLOPT_HTTPHEADER, [        "Authorization: Bearer " . SB_SECRET_KEY,        "apikey: " . SB_SECRET_KEY    ]);        $resposta = curl_exec($ch);    $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);    curl_close($ch);    return ($httpCode === 200);}